"use client";

import * as React from "react";
import * as CheckboxPrimitive from "@radix-ui/react-checkbox";

import { cn } from "@/lib/utils";

export type OdsCheckboxProps = React.ComponentPropsWithoutRef<
  typeof CheckboxPrimitive.Root
>;

function OdsCheckboxCheckIcon(props: React.SVGProps<SVGSVGElement>) {
  return (
    <svg viewBox="0 0 12 9" fill="none" aria-hidden="true" {...props}>
      <path
        d="M10.5 1.5 4.667 7.333 1.5 4.167"
        stroke="currentColor"
        strokeWidth="2"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function OdsCheckboxIndeterminateIcon(props: React.SVGProps<SVGSVGElement>) {
  return (
    <svg viewBox="0 0 10 2" fill="none" aria-hidden="true" {...props}>
      <path
        d="M1 1h8"
        stroke="currentColor"
        strokeWidth="2"
        strokeLinecap="round"
      />
    </svg>
  );
}

export const OdsCheckbox = React.forwardRef<
  React.ElementRef<typeof CheckboxPrimitive.Root>,
  OdsCheckboxProps
>(({ className, ...props }, ref) => (
  <CheckboxPrimitive.Root
    ref={ref}
    className={cn(
      "group flex size-5 shrink-0 items-center justify-center rounded-[4px] bg-[var(--bg-secondary)] text-[var(--fg-base)] outline-none transition-[background-color,box-shadow,opacity] data-[state=checked]:bg-[var(--bg-primary)] data-[state=indeterminate]:bg-[var(--bg-primary)] focus-visible:ring-[3px] focus-visible:ring-[var(--border-primary)] disabled:cursor-not-allowed disabled:opacity-50",
      className
    )}
    {...props}
  >
    <CheckboxPrimitive.Indicator
      className={cn(
        "flex items-center justify-center",
        "[&[data-state=checked]_.ods-checkbox-check]:block",
        "[&[data-state=indeterminate]_.ods-checkbox-indeterminate]:block"
      )}
    >
      <OdsCheckboxCheckIcon className="ods-checkbox-check hidden h-[9px] w-3" />
      <OdsCheckboxIndeterminateIcon className="ods-checkbox-indeterminate hidden h-0.5 w-2.5" />
    </CheckboxPrimitive.Indicator>
  </CheckboxPrimitive.Root>
));

OdsCheckbox.displayName = "OdsCheckbox";
